// components/fields/Password.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';

// Using your specified import paths
import type {IPassword, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {Flex, KitsInputPassword} from "../../../../_compat";

/**
 * Renders a password input with an optional strength meter.
 * All logic is handled by the useFieldLogic hook.
 */
export const Password = <T extends FieldValues>({
                                                    element,
                                                    control,
                                                    getValues,
                                                    fieldLogic,
                                                }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        isRequired,
        helperText,
        leftAddon,
        rightAddon,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    // 2. Cast the element to its specific type to access unique properties.
    const passwordElement = element as IPassword<T>;
    const {showStrengthProgress, toggleEye, localProps} = passwordElement;

    // 3. The component is now only responsible for rendering the UI.
    return (
        <KitsInputPassword
            // --- Core react-hook-form props ---
            {...field} // Spreads `onChange`, `onBlur`, `value`, `ref`

            // --- Resolved props from useFieldLogic ---
            id={field.name}
            label={label}
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            attached={attached}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
            showStrengthProgress={showStrengthProgress}

            // --- Props from the element definition ---
            toggleEye={toggleEye}
            {...localProps}
        />
    );
};

export default Password;
